    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    result = []
    for i, c in enumerate(s):
        if c.isalpha():
            if c.islower():
                result.append(c.upper())
