def strange_sort_list(lst):
    """
    Given list of integers, return list in strange order.
    Strange sorting, is when you start with the minimum value,
    then maximum of the remaining integers, then minimum and so on.
    """
    result = []
    n = len(lst)
    for i in range(n):
        if i == 0:
            result.append(lst[0])
        elif i == n - 1:
            result.append(lst[n - 1])
        else:
            # Find the pivot index that splits the array
            pivot = i
            for j in range(i + 1, n):
                if lst[j] < lst[pivot]:
                    pivot = j
            # The pivot is now the index of the minimum of the rest
            result.append(lst[pivot])
            # Append the rest in reverse order
            rest = lst[i + 1:]
            for j in range(len(rest) - 1, i - 1, -1):
                result.append(rest[j])
    return result

