    total_match(['4'], ['1', '2', '3', '4', '5']) ➞ ['4']
    '''
    def get_char_count(s):
        return len(s)

    def get_total_chars(lst):
        total = 0
        for s in lst:
            total += get_char_count(s)
        return total

    def is_less(lst1, lst2):
        return get_total_chars(lst1) < get_total_chars(lst2)

    def is_same(lst1, lst2):
        return get_total_chars(lst1) == get_total_chars(lst2)

    if is_less(lst1, lst2):
        return lst1
    elif is_same(lst1, lst2):
        return lst1
    else:
        return lst2

