def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    # Convert the number to a string, handling negative signs as just stripping them
    s = str(num)

    even_count = 0
    odd_count = 0

    for digit in s:
        if digit.isdigit():
            # For each digit, check if it's even
            if int(digit) % 2 == 0:
                even_count += 1
            else:
                odd_count += 1
        else:
            # If the digit is not a digit, it's negative, so it's odd
            odd_count += 1

    return (even_count, odd_count)

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    value = 0
    map = {1000: 'C', 900: 'CM', 500: 'D', 400: "CD", 100: "C", 90: "XC", 50: "L", 40: "XL", 30: "XXX", 20: "XX", 10: "X", 9: "IX", 5: "V", 4: "IV", 1: "I"}

    for n in range(1, 1000):
        if number % n == 0:
            value = value + map.get(n, 0)

    return "".join(map(lambda x: x.lower(), [str(v) for v in value]))

def find_max(words):
    """Write a function that accepts a list of strings.
    The list contains different words. Return the word with maximum number
    of unique characters. If multiple strings have maximum number of unique
    characters, return the one which comes first in lexicographical order.

    find_max(["name", "of", "string"]) == "string"
    find_max(["name", "enam", "game"]) == "enam"
    find_max(["aaaaaaa", "bb" ,"cc"]) == ""aaaaaaa"
    """
    # Calculate the length of unique characters for each string
    def count_unique_chars(word):
        set_char = set()
        for char in word:
            set_char.add(char)
        return len(set_char)

    max_length = 0
    best_word = ""

    for word in words:
        length = count_unique_chars(word)
        if length > max_length:
            max_length = length
            best_word = word
        elif length == max_length:
            if best_word is None or word < best_word:
                best_word = word

    return best_word

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    if not s:
        return s

    # Build a new string with each character in reverse order
    result = []
    for i in range(len(s) - 1, -1, -1):
        char = s[i]
        if char.isalpha():
            # Determine case
            if char.islower():
                char = char.upper()
            else:
                char = char.lower()
        result.append(char)

    return "".join(result)

