        raise ValueError("n must be a positive integer")

    if n == 1:
        return 2  # 1 and 11 are the only 1-digit numbers starting or ending with 1

    count = 0
    for i in range(1, 10):
        # Numbers starting with 1: 100...1 (100 to 999)
        for j in range(1, 10):
