        count = 0
        for i in range(1, n + 1):
            if is_palindrome(i):
                if i % 2 == 0:
                    count += 1
        return count

    def count_odd_palindromes(n):
        count = 0
        for i in range(1, n + 1):
            if is_palindrome(i):
                if i % 2 != 0:
                    count += 1
        return count

    return (count_even_palindromes(n), count_odd_palindromes(n))

