def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    # Return n if n <= 1
    if n <= 1:
        return n

    # Find the smallest prime factor and use it to iterate backwards
    p = 2
    while p * p <= n:
        if n % p == 0:
            # n is divisible by p
            while n % p == 0:
                n //= p
            break
        p += 1
    # n is still composite or prime
    if n == 1:
        return n

    # If n is still composite, the largest divisor is the largest prime factor < n
    p = 2
    while p * p <= n:
        if n % p == 0:
            while n % p == 0:
                n //= p
            break
        p += 1
    # If n is still composite, it's a prime number itself
    if n == 1:
        return n

    return n

