        return sum(1 for x in range(start, end + 1) if x % end == e)

    def count_e(s):
        # count integers in [1, 10^s] that end with s
        # such that the first digit is 1
        s = 10**s
        end = s * 10
        return sum(1 for x in range(1, end + 1) if x % s == s and x == 1)

