def encode(message):
    """
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    result = []

    for char in message:
        if char.isalpha():
            if char.islower():
                char = chr(ord(char) + 32)  # swap case (lower -> upper)
            elif char.isupper():
                char = chr(ord(char) - 32)  # swap case (upper -> lower)
            else:
                continue

            if char in 'AEIOUaeiou':
                # Replace vowel with the letter that appears 2 places ahead in English alphabet
                # A->H, E->K, I->J, O->L, U->T
                result.append(chr(ord(char) + 10))
            else:
                result.append(char)
        else:
            result.append(char)

    return ''.join(result)

